111→    private void handleHeartbeatMessage(WebSocketSession session, String messageContent) {
112→        try {
113→            if ("ping".equals(messageContent)) {
114→                // 客户端发来ping，回复pong
115→                session.sendMessage(new TextMessage("pong"));
116→                log.debug("收到ping，回复pong: {}", session.getId());
117→            } else if ("pong".equals(messageContent)) {
118→                // 客户端回复pong，记录心跳时间
119→                log.debug("收到pong响应: {}", session.getId());
120→            }
121→        } catch (IOException e) {
122→            log.error("发送心跳响应失败: {}", e.getMessage(), e);
123→        }
124→    }
